class Solution:
    def maxPoints(self, grid, queries):
        from collections import deque
        m, n = len(grid), len(grid[0])

        def count_reachable(q):
            if grid[0][0] >= q:
                return 0
            visited = [[False] * n for _ in range(m)]
            visited[0][0] = True
            dq = deque([(0, 0)])
            count = 0
            while dq:
                r, c = dq.popleft()
                count += 1
                for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n and not visited[nr][nc] and grid[nr][nc] < q:
                        visited[nr][nc] = True
                        dq.append((nr, nc))
            return count

        return [count_reachable(q) for q in queries]

